#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *parent = (int*)calloc(N+1, sizeof(int));
        int *depth = (int*)calloc(N+1, sizeof(int));
        for(int i=0;i<N;i++){
            int p,v; scanf("%d %d", &p, &v);
            parent[v]=p;
        }
        // compute depth using parent links (tree is rooted at 1)
        depth[1]=0;
        for(int i=2;i<=N;i++){
            int cur=i, d=0;
            while(cur!=1 && depth[cur]==0){
                cur=parent[cur];
                d++;
            }
            depth[i]=depth[parent[i]]+1;
        }
        int a,b,c; scanf("%d %d %d", &a, &b, &c);
        // helper lambda for LCA of two nodes
        int lca(int x, int y){
            while(depth[x] > depth[y]) x = parent[x];
            while(depth[y] > depth[x]) y = parent[y];
            while(x!=y){ x = parent[x]; y = parent[y]; }
            return x;
        }
        int l = lca(a,b);
        int ans = lca(l,c);
        printf("%d\n", ans);
        free(parent); free(depth);
    }
    return 0;
}

