        // compute depth by traversing parent chain (tree size ≤1e5, recursion safe)
        function<int(int)> getDepth = [&](int node){
            if(node==1) return 0;
            if(depth[node]) return depth[node];
            return depth[node]=getDepth(parent[node])+1;
        };
        for(int i=2;i<=N;i++) getDepth(i);
        int a,b,c; cin>>a>>b>>c;
        auto lca = [&](int x,int y){
            while(depth[x]>depth[y]) x=parent[x];
            while(depth[y]>depth[x]) y=parent[y];
            while(x!=y){ x=parent[x]; y=parent[y]; }
            return x;
        };
        int l = lca(a,b);
        int ans = lca(l,c);
        cout<<ans<<"\n";
    }
    return 0;
