import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        parent = [0]*(N+1)
        depth = [0]*(N+1)
        for __ in range(N):
            p = int(next(it)); v = int(next(it))
            parent[v] = p
        # compute depth recursively with memoisation
        sys.setrecursionlimit(200000)
        def get_depth(v):
            if v == 1:
                return 0
            if depth[v]:
                return depth[v]
            depth[v] = get_depth(parent[v]) + 1
            return depth[v]
        for node in range(2, N+1):
            get_depth(node)
        a = int(next(it)); b = int(next(it)); c = int(next(it))
        def lca(x, y):
            while depth[x] > depth[y]:
                x = parent[x]
            while depth[y] > depth[x]:
                y = parent[y]
            while x != y:
                x = parent[x]
                y = parent[y]
            return x
        l = lca(a, b)
        ans = lca(l, c)
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

